"""
This module contains the main game logic for Checkers (Draughts).
"""

class Piece:
    def __init__(self, color):
        self.color = color

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        # Initialize board with pieces
        for i in range(3):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece("black")
        for i in range(5, 8):
            for j in range(1, 8, 2):
                self.board[i][j] = Piece("white")

    def display(self):
        for row in self.board:
            print(" ".join(["X" if piece else "O" for piece in row]))

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = "black"

    def take_turn(self):
        # Get player move
        start, end = input(f"{self.current_player}'s turn. Enter move (e.g., a1-b2): ").split('-')
        start = ord(start[0]) - 97, int(start[1]) - 1
        end = ord(end[0]) - 97, int(end[1]) - 1

        # Validate and update board
        if self.board.board[start[0]][start[1]]:
            piece = self.board.board[start[0]][start[1]]
            if piece.color == self.current_player:
                if self.is_valid_move(start, end):
                    self.board.board[end[0]][end[1]] = piece
                    self.board.board[start[0]][start[1]] = None
                    self.switch_turn()
                else:
                    print("Invalid move. Try again.")
            else:
                print("It's not your turn. Try again.")
        else:
            print("No piece at the start position. Try again.")

    def is_valid_move(self, start, end):
        # Simple check (replace with actual game logic)
        return True

    def switch_turn(self):
        self.current_player = "white" if self.current_player == "black" else "black"

def run():
    game = CheckersGame()
    while True:
        game.display()
        game.take_turn()

if __name__ == "__main__":
    run()
```

